<template>
    <main class="musiques">
        <h1 class="title">{{ titre }}</h1>

        <div v-if="description!==null" class="description">{{ description }}</div>

        <div class="list">
            <a
                :key="m.key"
                class="list__item link"
                target="_blank"
                v-for="m in news"
                :href="m.youtube"
            >{{ m.titre }}</a>
        </div>

        <div style="border-bottom: 4px solid lightgrey"></div>

        <div v-if="!loading" class="list">
            <a
                :key="m.key"
                class="list__item link"
                target="_blank"
                v-for="m in list"
                :href="m.youtube"
            >{{ m.titre }}</a>
        </div>

         <div v-else class="loading">
            <div class="loading__body">
                <div class="loading__container">
                </div>
            </div>
        </div>
    </main>
</template>

<script>
import UiCard from '@/components/card'

import { mapActions, mapState } from 'vuex'

export default {
    name: 'Musiques',

    components: {
        UiCard
    },

    data() {
        return {
            loading: true,
            titres: {
                chill: 'Musiques Chill / Relax',
                troll: 'Musiques Troll / Révolutionnaire',
            },
            descriptions: {
                chill: null,
                troll: 'De la musique pour ceux qui ont des (sérieux) doutes sur nos systèmes, nos sociétés et la marche du monde en général, mais qui n’ont pas (encore) envie de se flinguer…',
            }
        };
    },

    computed: {
        ...mapState({
            musiques: state => state['musiques'].musiques
        }),

        list() {
            return !this.loading && this.musiques.filter(m => m[this.$route.params.type]);
        },

        news() {
            const last = new Date();
            last.setDate(last.getDate() - 14);
            
            return !this.loading && this.list.filter(m => {
                return Date.parse(m.created_on) > last.getTime();
            });
        },

        olds() {

        },

        description() {
            return this.descriptions[this.$route.params.type];
        },

        titre() {
            return this.titres[this.$route.params.type];
        },
    },

    methods: {
        ...mapActions({
            find: 'musiques/find'
        }),
    },

    mounted() {
        this.find()
            .then(() => this.loading = false)
            .catch((error) => console.error(error));
    }
}
</script>
