<template>
    <main class="chroniques">
        <h1 class="title">Petites chroniques de la Wallonie profonde</h1>
        
        <div class="description">
            <p>Citoyen(ne)s Wallon(ne)s et étrangers-ères, mères de famille, employé(e)s de bureau, 
                adolescent(e)s affamé(e)s, chômeurs, retraité(e)s, anciens sportifs, anciennes étoiles, 
                buveurs, fumeuses, lecteurs, peureux et bon-vivants en tout genre…</p>

            <p>Voici le fruit de mes réflexions déjantées et de maintes observations. Voici la description
                ordinaire mais effrayante de mon quotidien de jeune, de femme, tour à tour étudiante,
                demandeuse d’emploi, employée, écrivaine, bénévole dans notre versant francophone et
                plus accidenté du plat pays.</p>

            <p>Voici (roulement de tambours), en exclusivité, <span class="title__highlight">Les petites chroniques de la Wallonie
                Profonde</span> (terre prochainement indépendante) !</p>    
        </div>

        <div v-if="!loading" class="list">
            <router-link        
                v-for="c in chroniques"
                :key="c.titre" 
                tag="div"
                class="list__item link" 
                :to="{ name: 'rire-chronique', params: { id: c.id } }"
                v-html="c.titre"/>
        </div>

        <div v-else class="loading">
            <div class="loading__body">
                <div class="loading__container">
                </div>
            </div>
        </div>
    </main>
</template>

<script>
import UiCard from '@/components/card'

import Articles from './articles/articles'
import { mapState, mapActions } from 'vuex';

export default {
    name: 'Rire',

    components: {
        UiCard
    },

    data() {
        return {
            loading: true,
        }
    },

    computed: {
        ...mapState({
            chroniques: state => state.chroniques.chroniques    
        }),
    },

    methods: {
        ...mapActions({
            find: 'chroniques/find',
        }),
    },

    mounted() {
        if(this.chroniques.length === 0) {
            this.find()
            .then((chroniques) => {
                this.loading = false;
            })
            .catch((error) => {
                console.error(error);
            });
        } else {
            this.loading = false;
        }
    },
}
</script>
