<template>
    <main v-if="!loading" class="chronique">
        <h1 class="title" v-html="chronique.titre"></h1>
        
        <div class="article" v-html="chronique.contenu"></div>

        <!-- <div class="signature">
            <h2 :class="article.signature.color" v-html="article.signature.value"></h2>
        </div> -->


        <div class="back">
            <button class="button__back" @click="onBack">
                <back class="button__icon" />
                Retour
            </button>
        </div>
    </main>
</template>

<script>
import UiCard from '@/components/card'

import Back from '@/components/svg/arrow'
import { mapState, mapActions } from 'vuex';

export default {
    name: 'Rire',

    components: {
        UiCard,
        Back
    },

    data() {
        return {
            loading: true
        }
    },

    computed: {
        ...mapState({
            chronique: state => state.chroniques.chronique,
        }),
    },

    methods: {
        ...mapActions({
            view: 'chroniques/view'    
        }),

        onBack() {
            this.$router.push({
                name: 'rire-chroniques'
            });
        },
    },

    mounted() {
        this.view(this.$route.params.id) 
            .then((chronique) => {
                console.log(chronique);
                this.loading = false;
            })
            .catch((error) => { 
                console.error(error);
            });
    }
}
</script>
