<template>
    <main class="story">
        <h1 class="title">
            {{ story.title }}
        </h1>
        
        <div class="description">
            <component
                v-for="(c, i) in story.introduction"
                :key="i"
                :is="c.tag"
                v-html="c.value"
            />
        </div>
        
        <div v-if="!loading">
            <details class="chapter" :open="isOpen(j)" v-for="(c, j) in chapters" :key="c.id">
                <summary class="chapter__title" @click.stop.prevent="toggle(c, j)">
                    {{ c.titre }} ({{ c.partie }})

                    <span class="date">Posté le {{c.date_post}}</span>
                </summary>

                <div class="article" v-html="c.contenu"></div>
            </details>
        </div>

        <div v-else class="loading">
            <div class="loading__body">
                <div class="loading__container">
                </div>
            </div>
        </div>

        <div class="back">
            <button class="button__back" @click="onBack">
                <back class="button__icon" />
                Retour
            </button>
        </div>
    </main>
</template>

<script>
import UiCard from '@/components/card'

import Story from './2100'
import Back from '@/components/svg/arrow'
import { mapState, mapActions } from 'vuex'

export default {
    name: 'Fantasy2100',

    components: {
        UiCard,
        Back
    },

    data() {
        return {
            loading: true,
            selected: false,
            selection: null,  
        };
    },

    computed: {
        ...mapState({
            fantasies: state => state.fantasies.fantasies
        }),

        chapters() {
            return this.fantasies;
        },
        
        story() {
            return Story;
        }
    },

    methods: {
        ...mapActions({ 
            find: 'fantasies/find'    
        }),

        toggle(chapter, id) {            
            if(this.selection !== null) {
                if(this.selection === id) {
                    this.selected = false;
                    this.selection = null;
                } else {
                    this.selected = true;
                    this.selection = id;
                }
            } else {
                this.selected = true;
                this.selection = id;
            }
        },

        isOpen(id) {
            return this.selected && this.selection === id;
        },

        onBack() {
            this.$router.push({
                name: 'evasion-fantasy'
            })
        }
    },

    mounted() {
        this.find() 
            .then((fantasies) => this.loading = false)
            .catch((error) => console.error(error));
    }
}
</script>
